const articles = [{id: 1, title: 'SQL Guide'}, {id: 2, title: 'JS Tips'}];
const found = articles.filter(a => a.title.includes('sql'));
console.log(found);

List<Map> articles = List.of(
  Map.of("id", 1, "title", "SQL Guide"),
  Map.of("id", 2, "title", "JS Tips")
);
List<Map> found = articles.stream()
    .filter(a -> ((String)a.get("title")).contains("SQL"))
    .collect(Collectors.toList());
